  (1, 100), (1, 200), (1, 300),
  (2, 100), (2, 200),
  (3, 100), (3, 300),
  (4, 200), (4, 300),
  (5, 100), (5, 200),
  (6, 100), (6, 200), (6, 400);
SELECT a.product_id AS p1, b.product_id AS p2, COUNT(*) AS pair_count
FROM orders a JOIN orders b ON a.customer_id = b.customer_id AND a.product_id < b.product_id
GROUP BY a.product_id, b.product_id ORDER BY pair_count DESC LIMIT 10;

SELECT emp_id, period, score,
  AVG(score) OVER (PARTITION BY emp_id ORDER BY period ROWS BETWEEN 2 PRECEDING AND CURRENT ROW) AS rolling3
FROM productivity;

SELECT o.order_id,
  o.original_total - COALESCE(o.discount,0) - COALESCE(r.retro_discount,0) AS final_total
FROM orders o LEFT JOIN retro r ON o.order_id = r.order_id;

SELECT year, amount,
  100.0*(amount-LAG(amount) OVER (ORDER BY year))/NULLIF(LAG(amount) OVER (ORDER BY year),0) AS yoy_pct
FROM revenue;

SELECT movie_id, week, gross,
  gross - LAG(gross) OVER (PARTITION BY movie_id ORDER BY week) AS week_change
FROM box_office;

SELECT customer_id FROM (
  SELECT customer_id, SUM(amount) AS total FROM orders GROUP BY customer_id ORDER BY total DESC LIMIT 10
) t;

SELECT product_id,
  100.0*SUM(CASE WHEN status='cancelled' THEN 1 ELSE 0 END)/COUNT(*) AS cancel_rate
FROM orders GROUP BY product_id HAVING 100.0*SUM(CASE WHEN status='cancelled' THEN 1 ELSE 0 END)/COUNT(*) > 5;

SELECT c.name, SUM(s.amount) AS revenue, c.spend, SUM(s.amount)/NULLIF(c.spend,0) AS roas
FROM campaigns c LEFT JOIN sales s ON c.campaign_id = s.campaign_id
GROUP BY c.name, c.spend;

SELECT AVG(o.amount) AS vip_avg
FROM customers c JOIN orders o ON c.customer_id = o.customer_id
WHERE c.is_vip::int = 1;

SELECT CAST(TO_CHAR(sale_date, 'MM') AS INTEGER) AS mo, SUM(amount) AS total,
  RANK() OVER (ORDER BY SUM(amount) DESC) AS rk
FROM sales GROUP BY CAST(TO_CHAR(sale_date, 'MM') AS INTEGER);

SELECT period, amount,
  AVG(amount) OVER (ORDER BY period ROWS BETWEEN 6 PRECEDING AND CURRENT ROW) AS rolling_7
FROM profit;

SELECT 100.0 * COUNT(DISTINCT a.user_id) / COUNT(DISTINCT u.user_id) AS activation_rate
FROM users u LEFT JOIN activity a
  ON u.user_id=a.user_id AND a.action_date <= (u.signup_date + INTERVAL '+7 days');

SELECT posted_date, SUM(likes+comments) AS engagement,
  AVG(SUM(likes+comments)) OVER (ORDER BY posted_date ROWS BETWEEN 6 PRECEDING AND CURRENT ROW) AS rolling
FROM posts GROUP BY posted_date;

SELECT user_id, song_id, played_at,
  COUNT(*) OVER (PARTITION BY user_id, song_id ORDER BY played_at) AS cumulative_plays
FROM plays;

SELECT * FROM (
  SELECT *, ROW_NUMBER() OVER (PARTITION BY customer_id ORDER BY order_date DESC) rn FROM orders
) t WHERE rn=1;

SELECT p.name, SUM(oi.qty) AS units
FROM order_items oi JOIN products p ON oi.product_id = p.product_id
GROUP BY p.name ORDER BY units DESC LIMIT 5;

SELECT product_id, SUM(amount) AS total,
  RANK() OVER (ORDER BY SUM(amount) DESC) AS rk
FROM sales GROUP BY product_id;

SELECT dept_id, AVG(salary) AS dept_avg,
  (SELECT AVG(salary) FROM employees) AS overall_avg
FROM employees GROUP BY dept_id;

SELECT * FROM customers c JOIN
(SELECT customer_id, SUM(amount) AS total FROM orders GROUP BY customer_id) o
ON c.customer_id = o.customer_id;

SELECT e.emp_id, e.name, COUNT(pa.project_id) AS projects
FROM employees e LEFT JOIN project_assignments pa ON e.emp_id = pa.emp_id
GROUP BY e.emp_id, e.name;

