SELECT DATE_TRUNC('month', scheduled_date)::DATE AS mo,
  AVG(actual_date - scheduled_date) AS avg_delay_days
FROM shipments GROUP BY DATE_TRUNC('month', scheduled_date)::DATE;

SELECT week_start, visits,
  100.0*(NULLIF(regexp_replace(visits::text, '[^-.0-9]', '', 'g'), '')::numeric - LAG(NULLIF(regexp_replace(visits::text, '[^-.0-9]', '', 'g'), '')::numeric) OVER (ORDER BY week_start))/NULLIF(LAG(NULLIF(regexp_replace(visits::text, '[^-.0-9]', '', 'g'), '')::numeric) OVER (ORDER BY week_start), 0) AS wow_pct
FROM traffic;

DROP TABLE IF EXISTS invoices;
CREATE TABLE invoices (invoice_id INT, due_date DATE, paid_date DATE);
